# ❌ ANTI-PATTERN: Recomputing features from scratch for every prediction
class PoorCricketPredictor:
    def predict_runs(self, player_id, upcoming_match):
        # Fetches entire career history every time
        all_innings = database.fetch_all_innings(player_id)
        avg_runs = sum(all_innings) / len(all_innings)  # Inefficient!
        return model.forward(avg_runs)

# ✅ BEST PRACTICE: Stateful accumulator with cached features
class OptimalCricketPredictor:
    def __init__(self):
        self.player_stats_cache = {}  # Rolling stats
        self.cache_timestamp = {}

    def update_player_form(self, player_id, latest_innings_score):
        """Update rolling statistics efficiently"""
        if player_id not in self.player_stats_cache:
            self.player_stats_cache[player_id] = {
                'form_index': 0,  # Last 5 innings weighted avg
                'momentum': 0,    # Trend indicator
                'consistency': 0  # Standard deviation of recent scores
            }

        stats = self.player_stats_cache[player_id]
        # Exponential moving average (recent matches weighted higher)
        stats['form_index'] = 0.7 * stats['form_index'] + 0.3 * latest_innings_score
        stats['momentum'] = latest_innings_score - stats['form_index']
        self.cache_timestamp[player_id] = time.time()

    def predict_runs(self, player_id, upcoming_match):
        """Use cached features for fast prediction"""
        # Check cache freshness (invalidate if > 24 hours old)
        if time.time() - self.cache_timestamp.get(player_id, 0) > 86400:
            self.update_player_form(player_id, self._fetch_latest_score(player_id))

        stats = self.player_stats_cache[player_id]
        prediction_input = torch.tensor([
            stats['form_index'],
            stats['momentum'],
            stats['consistency'],
            upcoming_match.opposition_strength
        ])
        return self.model.forward(prediction_input)
